def remove_duplicates(lst):
    seen = set()
    result = []
    for item in lst:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result
Time complexity: O(n), Space complexity: O(n)

def find_peak(arr):
    if len(arr) == 1:
        return 0
    left, right = 0, len(arr) - 1
    while left < right:
        mid = (left + right) // 2
        if arr[mid] < arr[mid + 1]:
            left = mid + 1
        else:
            right = mid
    return left
For [1, 3, 4, 2, 1], returns index 2 (value 4)

def reverse_string(s):
    chars = list(s)
    left, right = 0, len(chars) - 1
    while left < right:
        chars[left], chars[right] = chars[right], chars[left]
        left += 1
        right -= 1
    return ''.join(chars)
Alternatively using recursion or loop. For 'hello', returns 'olleh'.
